async function run(input) {
  var titel = String((input && input.titel) || '').trim();
  var start = String((input && input.start) || '').trim();
  var ende = String((input && input.ende) || '').trim();
  var ort = String((input && input.ort) || '').trim();
  var beschreibung = String((input && input.beschreibung) || '').trim();
  if (!titel) return { fehler: 'Titel fehlt.' };
  if (!start) return { fehler: 'Startzeit fehlt.' };
  function fmt(d) {
    if (isNaN(d.getTime())) return null;
    function p(n) { return String(n).padStart(2, '0'); }
    return d.getUTCFullYear() + p(d.getUTCMonth() + 1) + p(d.getUTCDate()) + 'T' + p(d.getUTCHours()) + p(d.getUTCMinutes()) + p(d.getUTCSeconds()) + 'Z';
  }
  function esc(s) { return String(s || '').replace(/\\/g, '\\\\').replace(/;/g, '\\;').replace(/,/g, '\\,').replace(/\n/g, '\\n'); }
  var ds = new Date(start);
  var dtStart = fmt(ds);
  if (!dtStart) return { fehler: 'Startzeit ungueltig (ISO-Format erwartet).' };
  var de = ende ? new Date(ende) : new Date(ds.getTime() + 3600000);
  var dtEnd = fmt(de);
  if (!dtEnd) return { fehler: 'Endzeit ungueltig.' };
  var dtStamp = fmt(new Date());
  var rnd = '';
  var bytes = new Uint8Array(16);
  crypto.getRandomValues(bytes);
  for (var i = 0; i < bytes.length; i++) rnd += bytes[i].toString(16).padStart(2, '0');
  var uid = rnd + '@astoris';
  var lines = [
    'BEGIN:VCALENDAR',
    'VERSION:2.0',
    'PRODID:-//Astoris//iCal Generator//DE',
    'CALSCALE:GREGORIAN',
    'BEGIN:VEVENT',
    'UID:' + uid,
    'DTSTAMP:' + dtStamp,
    'DTSTART:' + dtStart,
    'DTEND:' + dtEnd,
    'SUMMARY:' + esc(titel)
  ];
  if (ort) lines.push('LOCATION:' + esc(ort));
  if (beschreibung) lines.push('DESCRIPTION:' + esc(beschreibung));
  lines.push('END:VEVENT');
  lines.push('END:VCALENDAR');
  var ics = lines.join('\r\n');
  var base = titel.replace(/[^a-zA-Z0-9]+/g, '_').replace(/^_+|_+$/g, '').toLowerCase() || 'termin';
  return { ics: ics, dateiname: base + '.ics' };
}
